// ===== /src/components/WeatherApp.jsx =====
import React, { useMemo, useState, useEffect } from "react";
import SearchSection from "./SearchSection";
import Forecast from "./Forecast";
import Hourly from "./Hourly";
import BottomBar from "./BottomBar";

// Safe getter util (same behavior you were using)
const get = (obj, path, fallback = "") =>
  path.split(".").reduce((o, k) => (o && o[k] != null ? o[k] : null), obj) ?? fallback;

export default function WeatherApp({ data, onCityChange, onTabChange }) {
  // `data` is expected to come from your backend (current, hourly, daily)
  // Provide sane fallbacks so the UI doesn't explode while loading
  const current = get(data, "current", {});
  const hourly = useMemo(() => get(data, "hourly", []), [data]);
  const daily = useMemo(() => get(data, "daily", []), [data]);

  const [activeTile, setActiveTile] = useState(0); // 0=temp, 1=wind, 2=precip, ... as you expand
  const [favorites, setFavorites] = useState(() => {
    // load favorites from localStorage
    try {
      const raw = localStorage.getItem("favoriteCities");
      return raw ? JSON.parse(raw) : ["Atlanta, US", "Athens, US", "New York, US"]; 
    } catch {
      return ["Atlanta, US", "Athens, US", "New York, US"]; 
    }
  });

  useEffect(() => {
    try { localStorage.setItem("favoriteCities", JSON.stringify(favorites)); } catch {}
  }, [favorites]);

  const handleAddFavorite = (city) => {
    if (!city) return;
    setFavorites((prev) => (prev.includes(city) ? prev : [city, ...prev].slice(0, 10)));
  };

  const handleSelectCity = (city) => {
    if (onCityChange) onCityChange(city);
  };

  const tempNow = Math.round(get(current, "temp", get(current, "temperature", 0)));
  const description = get(current, "weather.0.description", get(current, "summary", ""));

  return (
    <div className="relative min-h-screen flex flex-col bg-white dark:bg-black text-gray-900 dark:text-gray-100">
      {/* Top Search (sleek) */}
      <div className="sticky top-0 z-30 backdrop-blur supports-[backdrop-filter]:bg-black/20 bg-black/10">
        <div className="mx-auto w-full max-w-4xl px-4 py-3">
          <SearchSection 
            favorites={favorites} 
            onSelectCity={handleSelectCity}
            onAddFavorite={handleAddFavorite}
          />
        </div>
      </div>

      {/* Main content */}
      <main className="flex-1 w-full mx-auto max-w-4xl px-4 pt-4 pb-24">
        {/* Weather Now card (glass + centered) */}
        <section className="mb-4">
          <div className="rounded-2xl p-5 shadow-lg border border-white/10 bg-white/10 dark:bg-white/5 backdrop-blur">
            <div className="flex items-center justify-between">
              <div>
                <h1 className="text-4xl font-semibold leading-none">{Number.isFinite(tempNow) ? `${tempNow}°` : "--"}</h1>
                <p className="text-sm opacity-80 mt-1 capitalize">{description || "Weather now"}</p>
              </div>
              <div className="text-right">
                <p className="text-xs opacity-70">Feels like {Math.round(get(current, "feels_like", tempNow))}°</p>
                <p className="text-xs opacity-70">Wind {Math.round(get(current, "wind_speed", 0))} mph</p>
              </div>
            </div>
          </div>
        </section>

        {/* Hourly tiles with mobile dots */}
        <section className="mb-6">
          <Hourly hourly={hourly} activeTile={activeTile} onActiveTileChange={setActiveTile} />
        </section>

        {/* 16-day Forecast (Apple-style thin rectangles on mobile, grid on desktop) */}
        <section className="mb-6">
          <Forecast daily={daily} />
        </section>
      </main>

      {/* Bottom bar */}
      <BottomBar onTabChange={onTabChange} />
    </div>
  );
}
